examples.original_ir:
define i32 @test(i1 %c, i8 %x) {
entry:
  br i1 %c, label %if.then, label %if.end

if.then:
  %ext = zext i8 %x to i32
  br label %if.end

if.end:
  %p = phi i32 [ %ext, %if.then ], [ undef, %entry ]
  %and = and i32 %p, 255
  ret i32 %and
}

